// Replace with Notion/Confluence API call for production
const docs = [
  { title: 'Product Roadmap — Q3 2026', owner: 'Head of Product', category: 'strategy', last_updated: '2026-07-01', stale_threshold_days: 14 },
  { title: 'API Authentication Guide', owner: 'Maria Santos', category: 'technical', last_updated: '2026-04-15', stale_threshold_days: 60 },
  { title: 'Onboarding Flow Spec', owner: 'Head of Product', category: 'product', last_updated: '2026-02-20', stale_threshold_days: 30 },
  { title: 'Design System Components', owner: 'James Kim', category: 'design', last_updated: '2026-06-28', stale_threshold_days: 30 },
  { title: 'Sprint Retro Template', owner: 'Alex Chen', category: 'process', last_updated: '2026-07-05', stale_threshold_days: 90 },
  { title: 'Incident Response Runbook', owner: 'Maria Santos', category: 'operations', last_updated: '2026-01-10', stale_threshold_days: 30 },
  { title: 'Pricing & Packaging Overview', owner: 'Head of Product', category: 'strategy', last_updated: '2026-05-01', stale_threshold_days: 60 }
];
const today = '2026-07-14';
return [{ json: { docs, today } }];

const { docs, today } = $input.first().json;
const todayMs = new Date(today).getTime();
const results = docs.map(doc => {
  const lastMs = new Date(doc.last_updated).getTime();
  const days_since_update = Math.floor((todayMs - lastMs)/(1000*60*60*24));
  const is_stale = days_since_update > doc.stale_threshold_days;
  const staleness_ratio = parseFloat((days_since_update / doc.stale_threshold_days).toFixed(2));
  const severity = staleness_ratio >= 3 ? 'critical' : staleness_ratio >= 2 ? 'warning' : is_stale ? 'stale' : 'fresh';
  return { ...doc, days_since_update, is_stale, staleness_ratio, severity };
});
const stale = results.filter(r => r.is_stale);
const by_severity = { critical: stale.filter(r=>r.severity==='critical'), warning: stale.filter(r=>r.severity==='warning'), stale: stale.filter(r=>r.severity==='stale') };
const by_owner = {};
stale.forEach(r => { if(!by_owner[r.owner]) by_owner[r.owner]=[]; by_owner[r.owner].push(r.title); });
return [{ json: { results, stale, by_severity, by_owner, today, meta: { total: docs.length, stale_count: stale.length, critical_count: by_severity.critical.length, fresh_count: results.length - stale.length } } }];

const { stale, by_severity, by_owner, meta: m, today } = $input.first().json;
const fmt = arr => arr.map(d => `  [${d.severity.toUpperCase()}] "${d.title}" — ${d.days_since_update}d since update (threshold ${d.stale_threshold_days}d) — owner: ${d.owner}`).join('\n');
const ownerLines = Object.entries(by_owner).map(([owner, docs]) => `  ${owner}: ${docs.join(', ')}`).join('\n');
const report = [
  `DOCUMENTATION FRESHNESS REPORT`,
  `As of: ${today} | Total: ${m.total} | Stale: ${m.stale_count} | Critical: ${m.critical_count} | Fresh: ${m.fresh_count}`,
  ``,
  by_severity.critical.length > 0 ? `CRITICAL (3x+ past due):\n${fmt(by_severity.critical)}` : '',
  by_severity.warning.length > 0 ? `\nWARNING (2x past due):\n${fmt(by_severity.warning)}` : '',
  by_severity.stale.length > 0 ? `\nSTALE (past threshold):\n${fmt(by_severity.stale)}` : '',
  ``,
  `BY OWNER (action required):`,
  ownerLines,
].filter(Boolean).join('\n');
return [{ json: { ...($input.first().json), report_text: report } }];
